+/// Handle LoRA management subcommands
+fn handleLoraCommand(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    subcmd: []const u8,
+    args: []const []const u8,
+) !void {
+    const lora_pool_mod = @import("lora_pool.zig");
+
+    // Load model (required for LoRA pool)
+    std.debug.print("Loading model: {s}\n", .{model_path});
+    var model = llama.Model.load(model_path, .{}) catch |err| {
+        std.debug.print("Failed to load model: {}\n", .{err});
+        return err;
+    };
+    defer model.deinit();
+
+    // Create LoRA pool (1GB budget)
+    var pool = try lora_pool_mod.LoraPool.init(allocator, &model, 1.0);
+    defer pool.deinit();
+
+    if (std.mem.eql(u8, subcmd, "load")) {
+        if (args.len < 2) {
+            std.debug.print("Error: Usage: zell lora <model> load <id> <path>\n", .{});
+            return error.InvalidArguments;
+        }
+        const id = args[0];
+        const path = args[1];
+
+        try pool.loadAdapter(id, path);
+        std.debug.print("✓ Loaded LoRA adapter '{s}'\n", .{id});
+    } else if (std.mem.eql(u8, subcmd, "list")) {
+        const adapter_ids = try pool.listAdapters(allocator);
+        defer {
+            for (adapter_ids) |id| allocator.free(id);
+            allocator.free(adapter_ids);
+        }
+
+        if (adapter_ids.len == 0) {
+            std.debug.print("No LoRA adapters loaded.\n", .{});
+            return;
+        }
+
+        std.debug.print("Loaded LoRA Adapters:\n", .{});
+        pool.mutex.lock();
+        defer pool.mutex.unlock();
+
+        for (adapter_ids, 1..) |id, i| {
+            const info = pool.adapters.get(id) orelse continue;
+
+            std.debug.print("{d}. {s} ({d} MB, used {d} times)\n", .{
+                i,
+                id,
+                info.size_bytes / (1024 * 1024),
+                info.usage_count,
+            });
+            std.debug.print("   Path: {s}\n", .{info.path});
+            std.debug.print("   Last used: {d}\n", .{info.last_used});
+
+            // Show alpha if available
+            if (info.metadata.get("adapter.lora.alpha")) |alpha_str| {
+                std.debug.print("   Alpha: {s}\n", .{alpha_str});
+            }
+            std.debug.print("\n", .{});
+        }
+
+        // Show memory stats
+        const stats = pool.getStats();
+        std.debug.print("Memory: {d:.0} MB / {d:.0} MB ({d:.0}% used)\n", .{
+            stats.total_memory_mb,
+            stats.max_memory_mb,
+            stats.utilization * 100,
+        });
+    } else if (std.mem.eql(u8, subcmd, "unload")) {
+        if (args.len < 1) {
+            std.debug.print("Error: Usage: zell lora <model> unload <id>\n", .{});
+            return error.InvalidArguments;
+        }
+        const id = args[0];
+
+        try pool.unloadAdapter(id);
+        std.debug.print("✓ Unloaded LoRA adapter '{s}'\n", .{id});
+    } else if (std.mem.eql(u8, subcmd, "info")) {
+        if (args.len < 1) {
+            std.debug.print("Error: Usage: zell lora <model> info <id>\n", .{});
+            return error.InvalidArguments;
+        }
+        const id = args[0];
+
+        pool.mutex.lock();
+        defer pool.mutex.unlock();
+
+        const info = pool.adapters.get(id) orelse {
+            std.debug.print("Error: Adapter '{s}' not found\n", .{id});
+            return error.AdapterNotFound;
+        };
+
+        std.debug.print("LoRA Adapter: {s}\n", .{id});
+        std.debug.print("Path: {s}\n", .{info.path});
+        std.debug.print("Size: {d} MB\n", .{info.size_bytes / (1024 * 1024)});
+        std.debug.print("Usage Count: {d}\n", .{info.usage_count});
+        std.debug.print("Last Used: {d}\n\n", .{info.last_used});
+
+        std.debug.print("Metadata:\n", .{});
+        var it = info.metadata.iterator();
+        while (it.next()) |entry| {
+            std.debug.print("  {s}: {s}\n", .{ entry.key_ptr.*, entry.value_ptr.* });
+        }
+    } else {
+        std.debug.print("Unknown subcommand: {s}\n", .{subcmd});
+        printLoraUsage();
+        return error.UnknownSubcommand;
+    }
+}
+
+fn printLoraUsage() void {
+    std.debug.print(
+        \\Usage: zell lora <model> <subcommand> [args]
+        \\
+        \\Subcommands:
+        \\  load <id> <path>  - Load a LoRA adapter
+        \\  list              - List loaded adapters
+        \\  unload <id>       - Unload an adapter
+        \\  info <id>         - Show adapter details
+        \\
+        \\Examples:
+        \\  zell lora model.gguf load my_style ~/.cache/zell/lora/my_style.lora
+        \\  zell lora model.gguf list
+        \\  zell lora model.gguf unload my_style
+        \\  zell lora model.gguf info my_style
+        \\
+    , .{});
+}
